mapper.select:
SELECT DECODE(u.MODL_CD,' ','ZZZZZ',s.MODEL_NAME) MODEL_NAME , DECODE(u.ACC_MODL_ID,' ','ZZZZZ',NVL(a.ACC_MODL_NM,' ')) ACC_MODL_NM , DECODE(LENGTH(u.ACC_SW_INST_VER) , 6, TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,1,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,4,3)) , 9, TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,1,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,4,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,7,3)) , 13, TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,1,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,4,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,7,3))||'-'||SUBSTR(u.ACC_SW_INST_VER,10,4) , u.ACC_SW_INST_VER ) ACC_SW_INST_VER , NVL(u.STB_QTY,0) STB_QTY, NVL(u.ACC_BT_CONN_QTY,0) ACC_BT_CONN_QTY, NVL(u.ACC_PAIRING_QTY,0) ACC_PAIRING_QTY FROM ( SELECT MODL_CD, ACC_MODL_ID, ACC_SW_INST_VER , STB_QTY, ACC_BT_CONN_QTY, ACC_PAIRING_QTY FROM ST_UPD_ACC_DISTB_STS_BY_SW_VER WHERE SUM_DY = #{sumDy}
AND scrbr_typ_cd = #{scrbrTypCd}
UNION ALL SELECT MODL_CD, ACC_MODL_ID, 'ZZZZZ' ACC_SW_INST_VER , SUM(STB_QTY) STB_QTY, SUM(ACC_BT_CONN_QTY) ACC_BT_CONN_QTY, SUM(ACC_PAIRING_QTY) ACC_PAIRING_QTY FROM ST_UPD_ACC_DISTB_STS_BY_SW_VER WHERE SUM_DY = #{sumDy}
AND scrbr_typ_cd = #{scrbrTypCd}
GROUP BY MODL_CD, ACC_MODL_ID UNION ALL SELECT MODL_CD, ' ' ACC_MODL_ID, 'ZZZZZ' ACC_SW_INST_VER , SUM(STB_QTY) STB_QTY, SUM(ACC_BT_CONN_QTY) ACC_BT_CONN_QTY, SUM(ACC_PAIRING_QTY) ACC_PAIRING_QTY FROM ST_UPD_ACC_DISTB_STS_BY_SW_VER WHERE SUM_DY = #{sumDy}
AND scrbr_typ_cd = #{scrbrTypCd}
GROUP BY MODL_CD UNION ALL SELECT ' ' MODL_CD, ' ' ACC_MODL_ID, 'ZZZZZ' ACC_SW_INST_VER , SUM(STB_QTY) STB_QTY, SUM(ACC_BT_CONN_QTY) ACC_BT_CONN_QTY, SUM(ACC_PAIRING_QTY) ACC_PAIRING_QTY FROM ST_UPD_ACC_DISTB_STS_BY_SW_VER WHERE SUM_DY = #{sumDy}
AND scrbr_typ_cd = #{scrbrTypCd}
) u, STB_MODEL s, DM_ACC_MODL_MST a WHERE 1=1 AND u.MODL_CD = s.MODEL_CODE(+) AND u.ACC_MODL_ID = a.ACC_MODL_ID(+) ORDER BY MODEL_NAME, ACC_MODL_NM, ACC_SW_INST_VER

SELECT DECODE(u.ACC_MODL_ID,' ','ZZZZZ',NVL(a.ACC_MODL_NM,' ')) ACC_MODL_NM , DECODE(LENGTH(u.ACC_SW_INST_VER) , 6, TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,1,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,4,3)) , 9, TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,1,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,4,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,7,3)) , 13, TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,1,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,4,3))||'.'||TO_NUMBER(SUBSTR(u.ACC_SW_INST_VER,7,3))||'-'||SUBSTR(u.ACC_SW_INST_VER,10,4) , u.ACC_SW_INST_VER ) ACC_SW_INST_VER , NVL(u.STB_QTY,0) STB_QTY, NVL(u.ACC_BT_CONN_QTY,0) ACC_BT_CONN_QTY, NVL(u.ACC_PAIRING_QTY,0) ACC_PAIRING_QTY FROM ( SELECT ACC_MODL_ID, ACC_SW_INST_VER , SUM(STB_QTY) STB_QTY, SUM(ACC_BT_CONN_QTY) ACC_BT_CONN_QTY, SUM(ACC_PAIRING_QTY) ACC_PAIRING_QTY FROM ST_UPD_ACC_DISTB_STS_BY_SW_VER WHERE SUM_DY = #{sumDy}
AND scrbr_typ_cd = #{scrbrTypCd}
GROUP BY ACC_MODL_ID, ACC_SW_INST_VER UNION ALL SELECT ACC_MODL_ID, 'ZZZZZ' ACC_SW_INST_VER , SUM(STB_QTY) STB_QTY, SUM(ACC_BT_CONN_QTY) ACC_BT_CONN_QTY, SUM(ACC_PAIRING_QTY) ACC_PAIRING_QTY FROM ST_UPD_ACC_DISTB_STS_BY_SW_VER WHERE SUM_DY = #{sumDy}
AND scrbr_typ_cd = #{scrbrTypCd}
GROUP BY ACC_MODL_ID UNION ALL SELECT ' ' ACC_MODL_ID, 'ZZZZZ' ACC_SW_INST_VER , SUM(STB_QTY) STB_QTY, SUM(ACC_BT_CONN_QTY) ACC_BT_CONN_QTY, SUM(ACC_PAIRING_QTY) ACC_PAIRING_QTY FROM ST_UPD_ACC_DISTB_STS_BY_SW_VER WHERE SUM_DY = #{sumDy}
AND scrbr_typ_cd = #{scrbrTypCd}
) u, DM_ACC_MODL_MST a WHERE 1=1 AND u.ACC_MODL_ID = a.ACC_MODL_ID(+) ORDER BY ACC_MODL_NM, ACC_SW_INST_VER
